 1	import * as React from 'react';
 2	
 3	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { icon } from '@kubevirt-utils/resources/vmi';
 6	import { Label } from '@patternfly/react-core';
 7	
 8	import VirtualMachineInstanceActions from '../list/components/VirtualMachineInstanceActions/VirtualMachineInstanceAction';
 9	import VirtualMachineInstanceBreadcrumb from '../list/components/VirtualMachineInstanceBreadcrumb/VirtualMachineInstanceBreadcrumb';
10	
11	type VirtualMachinesInstancePageHeaderProps = {
12	  vmi: V1VirtualMachineInstance;
13	};
14	
15	const VirtualMachinesInstancePageHeader: React.FC<VirtualMachinesInstancePageHeaderProps> = ({
16	  vmi,
17	}) => {
18	  const { t } = useKubevirtTranslation();
19	  const status = vmi?.status?.phase;
20	  const IconComponent = icon?.[status];
21	  return (
22	    <div className="co-m-nav-title co-m-nav-title--detail">
23	      <VirtualMachineInstanceBreadcrumb />
24	      <span className={'co-m-pane__heading'}>
25	        <h1 className="co-resource-item__resource-name">
26	          <span className={`co-m-resource-icon co-m-resource-icon--lg`}>{t('VMI')}</span>
27	          {vmi?.metadata?.name}{' '}
28	          <Label icon={<IconComponent />} isCompact>
29	            {status}
30	          </Label>
31	        </h1>
32	        <VirtualMachineInstanceActions vmi={vmi} />
33	      </span>
34	    </div>
35	  );
36	};
37	
38	export default VirtualMachinesInstancePageHeader;

